    location: 'Guadalajara',
    price: 1500,
    image: 'https://images.unsplash.com/photo-1464983953574-0892a716854b?auto=format&fit=crop&w=600&q=80',
    beds: 3,
    description: 'Casa amplia y cómoda, perfecta para familias y mascotas.'
