    beds: 2,
    description: 'Escápate a la naturaleza en esta cabaña de madera.'
  }
];

function fakeSleep(ms) {
  return new Promise(res => setTimeout(res, ms));
}

export default function MiniAirbnb() {
  const [view, setView] = useState('home'); // home, login, register, detail, myBookings
  const [auth, setAuth] = useState(null); // {username}
  const [users, setUsers] = useState([]); // {username, password, bookings: []}
  const [loginForm, setLoginForm] = useState({ username: '', password: '' });
  const [registerForm, setRegisterForm] = useState({ username: '', password: '', confirm: '' });
  const [error, setError] = useState('');
  const [selectedRoom, setSelectedRoom] = useState(null);
  const [bookingLoading, setBookingLoading] = useState(false);
  const [successMsg, setSuccessMsg] = useState('');

  // Helper: get current user object
  const getUser = () => users.find(u => u.username === auth?.username);

  // Home: list rooms
  function renderHome() {
    return (
      <div style={{ maxWidth: 1100, margin: '40px auto 0', padding: 24 }}>
        <Header />
        <h1 style={{ fontSize: 36, fontWeight: 700, letterSpacing: -1, color: '#222', marginBottom: 8 }}>Encuentra tu próxima estancia</h1>
        <p style={{ color: '#666', marginBottom: 32 }}>Reserva habitaciones únicas y vive una experiencia inolvidable.</p>
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(260px, 1fr))', gap: 28 }}>
          {ROOMS.map(room => (
            <div key={room.id} style={{ background: 'white', borderRadius: 14, boxShadow: '0 4px 24px rgba(80,80,120,0.10)', overflow: 'hidden', position: 'relative', transition: 'transform .2s', cursor: 'pointer', display: 'flex', flexDirection: 'column' }}
              onClick={() => { setSelectedRoom(room); setView('detail'); }}
              onMouseEnter={e => e.currentTarget.style.transform = 'translateY(-4px) scale(1.025)'}
              onMouseLeave={e => e.currentTarget.style.transform = 'none'}
            >
              <div style={{ height: 180, background: '#eee', backgroundImage: `url(${room.image})`, backgroundSize: 'cover', backgroundPosition: 'center' }} />
              <div style={{ padding: 18, flex: 1, display: 'flex', flexDirection: 'column', justifyContent: 'space-between' }}>
                <div>
                  <div style={{ fontWeight: 600, fontSize: 18, color: '#222', marginBottom: 4 }}>{room.title}</div>
                  <div style={{ color: '#764ba2', fontWeight: 500, fontSize: 15 }}>{room.location}</div>
                  <div style={{ color: '#999', fontSize: 14, margin: '6px 0 0', display: 'flex', alignItems: 'center' }}>
                    <BedIcon /> {room.beds} camas
                  </div>
                </div>
                <div style={{ marginTop: 14, fontWeight: 700, color: '#667eea', fontSize: 17 }}>
                  ${room.price} <span style={{ color: '#888', fontWeight: 400, fontSize: 14 }}>/ noche</span>
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>
    );
  }

  // Header/Nav
  function Header() {
    return (
      <div style={{ display: 'flex', alignItems: 'center', marginBottom: 30, justifyContent: 'space-between' }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
          <svg width={34} height={34} viewBox="0 0 40 40" style={{ marginRight: 6 }}><circle cx="20" cy="20" r="18" fill="#667eea" /><path d="M20 10 L30 32 H10 Z" fill="#fff" /></svg>
          <span style={{ fontWeight: 800, fontSize: 23, color: '#764ba2', letterSpacing: -1 }}>MiniAirbnb</span>
        </div>
        <div style={{ display: 'flex', gap: 16, alignItems: 'center' }}>
          {auth && (
            <>
              <button style={navBtn} onClick={() => setView('home')}>Explorar</button>
              <button style={navBtn} onClick={() => setView('myBookings')}>Mis Reservas</button>
              <span style={{ color: '#667eea', fontWeight: 600, marginLeft: 12 }}>Hola, {auth.username}</span>
              <button style={navBtnOutline} onClick={handleLogout}>Salir</button>
            </>
          )}
          {!auth && (
            <>
              <button style={navBtn} onClick={() => setView('login')}>Iniciar sesión</button>
              <button style={navBtnOutline} onClick={() => setView('register')}>Registrarse</button>
            </>
          )}
        </div>
      </div>
    );
  }

  // Login
  function renderLogin() {
    return (
      <div style={centerBox}>
        <Header />
        <form style={formCard} onSubmit={handleLogin}>
          <h2 style={formTitle}>Iniciar sesión</h2>
          {error && <div style={errorMsg}>{error}</div>}
          <input autoFocus style={input} placeholder="Usuario" value={loginForm.username} onChange={e => setLoginForm(f => ({ ...f, username: e.target.value }))} />
          <input style={input} placeholder="Contraseña" type="password" value={loginForm.password} onChange={e => setLoginForm(f => ({ ...f, password: e.target.value }))} />
          <button style={mainBtn}>Entrar</button>
          <div style={{ marginTop: 14, fontSize: 14, color: '#555' }}>
            ¿No tienes cuenta? <span style={{ color: '#667eea', cursor: 'pointer', fontWeight: 500 }} onClick={() => { setView('register'); setError(''); }}>Regístrate</span>
          </div>
        </form>
      </div>
    );
  }

  // Register
  function renderRegister() {
    return (
      <div style={centerBox}>
        <Header />
        <form style={formCard} onSubmit={handleRegister}>
          <h2 style={formTitle}>Crear cuenta</h2>
          {error && <div style={errorMsg}>{error}</div>}
          <input autoFocus style={input} placeholder="Usuario" value={registerForm.username} onChange={e => setRegisterForm(f => ({ ...f, username: e.target.value }))} />
          <input style={input} placeholder="Contraseña" type="password" value={registerForm.password} onChange={e => setRegisterForm(f => ({ ...f, password: e.target.value }))} />
          <input style={input} placeholder="Confirmar contraseña" type="password" value={registerForm.confirm} onChange={e => setRegisterForm(f => ({ ...f, confirm: e.target.value }))} />
          <button style={mainBtn}>Registrarse</button>
          <div style={{ marginTop: 14, fontSize: 14, color: '#555' }}>
            ¿Ya tienes cuenta? <span style={{ color: '#667eea', cursor: 'pointer', fontWeight: 500 }} onClick={() => { setView('login'); setError(''); }}>Inicia sesión</span>
          </div>
        </form>
      </div>
    );
  }

  // Room Detail
  function renderRoomDetail() {
    if (!selectedRoom) return null;
    const alreadyBooked = auth && getUser()?.bookings?.some(b => b.roomId === selectedRoom.id);
    return (
      <div style={{ maxWidth: 700, margin: '38px auto', padding: 24 }}>
        <Header />
        <div style={{ background: 'white', borderRadius: 16, boxShadow: '0 4px 24px rgba(80,80,120,0.12)', display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
          <div style={{ height: 310, background: '#eee', backgroundImage: `url(${selectedRoom.image})`, backgroundSize: 'cover', backgroundPosition: 'center' }} />
          <div style={{ padding: 26 }}>
            <div style={{ fontSize: 27, fontWeight: 700, color: '#222', marginBottom: 8 }}>{selectedRoom.title}</div>
            <div style={{ color: '#764ba2', fontWeight: 500, fontSize: 17, marginBottom: 6 }}>{selectedRoom.location}</div>
            <div style={{ color: '#999', fontSize: 15, marginBottom: 10, display: 'flex', alignItems: 'center' }}>
              <BedIcon /> {selectedRoom.beds} camas
            </div>
            <div style={{ fontSize: 16, color: '#444', marginBottom: 20 }}>{selectedRoom.description}</div>
            <div style={{ fontSize: 18, fontWeight: 700, color: '#667eea', marginBottom: 16 }}>
              ${selectedRoom.price} <span style={{ color: '#888', fontWeight: 400, fontSize: 15 }}>/ noche</span>
            </div>
            {successMsg && <div style={successMsgStyle}>{successMsg}</div>}
            {!auth && (
              <button style={mainBtn} onClick={() => setView('login')}>Inicia sesión para reservar</button>
            )}
            {auth && (
              <button
                style={{ ...mainBtn, background: alreadyBooked ? '#ccc' : mainBtn.background, cursor: alreadyBooked ? 'not-allowed' : 'pointer' }}
                disabled={bookingLoading || alreadyBooked}
                onClick={handleBookRoom}
              >
                {alreadyBooked ? 'Ya reservada' : (bookingLoading ? 'Reservando...' : 'Reservar ahora')}
              </button>
            )}
            <button style={backBtn} onClick={() => setView('home')}>← Volver al listado</button>
          </div>
        </div>
      </div>
    );
  }

  // My Bookings
  function renderMyBookings() {
    const user = getUser();
    const bookings = user?.bookings || [];
    return (
      <div style={{ maxWidth: 800, margin: '40px auto', padding: 24 }}>
        <Header />
        <h2 style={{ fontSize: 30, fontWeight: 700, color: '#222', marginBottom: 16 }}>Mis Reservas</h2>
        {bookings.length === 0 && <div style={{ color: '#666', marginTop: 30, fontSize: 18 }}>No tienes reservas aún.</div>}
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(260px, 1fr))', gap: 25 }}>
          {bookings.map(bk => {
            const room = ROOMS.find(r => r.id === bk.roomId);
            return (
              <div key={bk.roomId} style={{ background: 'white', borderRadius: 14, boxShadow: '0 4px 18px rgba(80,80,120,0.10)', overflow: 'hidden', display: 'flex', flexDirection: 'column' }}>
                <div style={{ height: 140, background: '#eee', backgroundImage: `url(${room.image})`, backgroundSize: 'cover', backgroundPosition: 'center' }} />
                <div style={{ padding: 16, flex: 1, display: 'flex', flexDirection: 'column', justifyContent: 'space-between' }}>
                  <div>
                    <div style={{ fontWeight: 600, fontSize: 18, color: '#222', marginBottom: 4 }}>{room.title}</div>
                    <div style={{ color: '#764ba2', fontWeight: 500, fontSize: 15 }}>{room.location}</div>
                  </div>
                  <div style={{ marginTop: 12, color: '#555', fontSize: 15 }}>Reservado el <span style={{ color: '#667eea', fontWeight: 600 }}>{bk.date}</span></div>
                  <button style={miniBtn} onClick={() => { setSelectedRoom(room); setView('detail'); }}>Ver detalles</button>
                </div>
              </div>
            );
          })}
        </div>
      </div>
    );
  }

  // --- Handlers ---
  function handleLogin(e) {
    e.preventDefault();
    setError('');
    const { username, password } = loginForm;
    const user = users.find(u => u.username === username);
    if (!user) return setError('Usuario no registrado');
    if (user.password !== password) return setError('Contraseña incorrecta');
    setAuth({ username });
    setLoginForm({ username: '', password: '' });
    setView('home');
  }

  function handleRegister(e) {
    e.preventDefault();
    setError('');
    const { username, password, confirm } = registerForm;
    if (!username || !password) return setError('Completa todos los campos');
    if (password.length < 4) return setError('La contraseña debe tener al menos 4 caracteres');
    if (password !== confirm) return setError('Las contraseñas no coinciden');
    if (users.some(u => u.username === username)) return setError('Usuario ya registrado');
    setUsers([...users, { username, password, bookings: [] }]);
    setAuth({ username });
    setRegisterForm({ username: '', password: '', confirm: '' });
    setView('home');
  }

  function handleLogout() {
    setAuth(null);
    setView('home');
  }

  async function handleBookRoom() {
    if (!auth || !selectedRoom) return;
    setBookingLoading(true);
    setSuccessMsg('');
    await fakeSleep(700);
    setUsers(us => us.map(u => {
      if (u.username !== auth.username) return u;
      if (u.bookings.some(b => b.roomId === selectedRoom.id)) return u;
      return {
        ...u,
        bookings: [
          ...u.bookings,
          { roomId: selectedRoom.id, date: new Date().toLocaleDateString() }
        ]
      };
    }));
    setBookingLoading(false);
    setSuccessMsg('¡Reserva exitosa!');
    setTimeout(() => setSuccessMsg(''), 1800);
  }

  // --- Styles ---
  const navBtn = {
    background: 'linear-gradient(135deg,#667eea,#764ba2)',
    color: 'white', border: 'none', borderRadius: 8, fontWeight: 600, fontSize: 15,
    padding: '8px 18px', cursor: 'pointer', transition: 'all .22s', boxShadow: '0 2px 10px rgba(102,126,234,.09)'
  };
  const navBtnOutline = {
    ...navBtn,
    background: 'white', color: '#764ba2', border: '2px solid #764ba2', boxShadow: 'none',
    transition: 'all .22s',
  };
  const mainBtn = {
    background: 'linear-gradient(135deg,#667eea,#764ba2)',
    color: 'white', border: 'none', borderRadius: 10, fontWeight: 700, fontSize: 17,
    padding: '12px 0', width: '100%', marginTop: 10, cursor: 'pointer', transition: 'all .22s',
    boxShadow: '0 3px 16px rgba(118,75,162,.11)'
  };
  const miniBtn = {
    background: 'linear-gradient(135deg,#667eea,#764ba2)',
    color: 'white', border: 'none', borderRadius: 8, fontWeight: 600, fontSize: 14,
    padding: '7px 0', width: '100%', marginTop: 13, cursor: 'pointer', transition: 'all .22s',
    boxShadow: '0 2px 10px rgba(102,126,234,.09)'
  };
  const backBtn = {
    marginTop: 18, background: 'none', color: '#764ba2', border: 'none', fontSize: 16, cursor: 'pointer', fontWeight: 500, textDecoration: 'underline', padding: 0
  };
  const centerBox = {
    minHeight: '100vh', background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
    display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'flex-start', paddingTop: 55
  };
  const formCard = {
    background: 'white', borderRadius: 16, boxShadow: '0 4px 24px rgba(80,80,120,0.13)',
    padding: '38px 34px 30px', width: 350, display: 'flex', flexDirection: 'column', gap: 12
  };
  const input = {
    border: '1.5px solid #ececec', borderRadius: 7, padding: '10px 12px', fontSize: 15, outline: 'none', marginBottom: 2, transition: 'border .2s', fontFamily: 'inherit',
  };
  const formTitle = { fontSize: 25, fontWeight: 700, marginBottom: 9, color: '#222' };
  const errorMsg = { background: '#ffe2e2', color: '#c0392b', padding: '8px 13px', borderRadius: 7, marginBottom: 8, fontSize: 15 };
  const successMsgStyle = { background: '#e2ffe6', color: '#25a244', padding: '8px 13px', borderRadius: 7, marginBottom: 12, fontSize: 15 };

  // --- Icons ---
  function BedIcon() {
    return (
      <svg width={19} height={19} style={{ marginRight: 5, verticalAlign: 'middle' }} viewBox="0 0 20 20"><rect x="2" y="10" width="16" height="6" rx="2" fill="#667eea"/><rect x="3" y="7" width="5" height="3" rx="1.5" fill="#764ba2"/><rect x="12" y="7" width="5" height="3" rx="1.5" fill="#764ba2"/></svg>
    );
  }

  // --- Main Render ---
  return (
    <div style={{ fontFamily: '-apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif', minHeight: '100vh', background: 'linear-gradient(135deg, #f3f0ff 0%, #e9eafe 100%)' }}>
      {view === 'home' && renderHome()}
      {view === 'login' && renderLogin()}
      {view === 'register' && renderRegister()}
      {view === 'detail' && renderRoomDetail()}
      {view === 'myBookings' && renderMyBookings()}
      <div style={{ textAlign: 'center', color: '#aaa', fontSize: 14, margin: '60px 0 10px' }}>
        <span>MiniAirbnb — Demo UI • <span style={{ color: '#764ba2', fontWeight: 500 }}>2024</span></span>
      </div>
    </div>
  );
}
